/**
 * PressVideo — Analytics admin dashboard.
 * Requires Chart.js 4.x loaded as a dependency.
 */
(function () {
	'use strict';

	var cfg     = window.pvAnalytics || {};
	var ajaxUrl = cfg.ajaxUrl || '';
	var nonce   = cfg.nonce   || '';

	var activeDays  = 30;
	var demoMode    = false;
	var trendChart  = null;
	var topChart    = null;
	var depthChart  = null;

	// ── Sample data for demo preview ──────────────────────────────────
	var DEMO_TITLES = [
		'How I Grew My Channel to 10K Subscribers',
		'Best Camera Setup for YouTube Beginners (2024)',
		'My Full Studio Tour — $0 to $3K Setup',
		'How to Edit Videos 10× Faster in Premiere',
		'Growing on YouTube Without Buying Ads',
		'The YouTube Algorithm: What Actually Works',
		'3 Thumbnail Mistakes Killing Your CTR',
		'One Year on YouTube — Honest Results',
		'How to Script a Video Without Sounding Robotic',
		'Repurposing YouTube Content for Every Platform',
	];

	function buildDemoData( days ) {
		var now   = new Date();
		var lbls  = [];
		var seed30 = [45,38,62,71,58,34,51,67,89,94,78,65,187,142,96,88,95,72,63,49,77,93,108,86,62,74,94,117,129,134];
		var vals  = [];
		for ( var i = days - 1; i >= 0; i-- ) {
			var dt  = new Date( now );
			dt.setDate( now.getDate() - i );
			var y   = dt.getFullYear();
			var m   = String( dt.getMonth() + 1 ).padStart( 2, '0' );
			var d   = String( dt.getDate() ).padStart( 2, '0' );
			lbls.push( y + '-' + m + '-' + d );
			// Scale values based on period
			var base = seed30[ i % 30 ];
			if ( days === 7 )       vals.push( Math.round( base * 1.15 ) );
			else if ( days === 90 ) vals.push( Math.round( base * 0.85 ) );
			else                    vals.push( base );
		}
		var totalPlays = vals.reduce( function(a,b){ return a+b; }, 0 );
		var topVideos  = DEMO_TITLES.map( function( title, i ) {
			return {
				title:       title,
				plays:       Math.max( 8, Math.round( totalPlays * (0.11 - i * 0.009) ) ),
				thumb:       '',
				edit:        '#',
				last_played: i < 3 ? 'Today' : ( i < 6 ? 'Yesterday' : '3 days ago' ),
			};
		} );
		return {
			stats: {
				total_plays:    totalPlays,
				unique_videos:  10,
				avg_completion: 63,
			},
			trend: { labels: lbls, values: vals },
			top_videos: topVideos.slice( 0, 5 ),
			depth: { d25: Math.round(totalPlays*0.64), d50: Math.round(totalPlays*0.43), d75: Math.round(totalPlays*0.24), d100: Math.round(totalPlays*0.11) },
			all_videos: topVideos,
		};
	}

	function enterDemoMode() {
		demoMode = true;
		var btn = document.getElementById( 'pva-demo-toggle' );
		if ( btn ) btn.classList.add( 'pva-demo-btn--active' );

		var existing = document.getElementById( 'pva-demo-notice' );
		if ( ! existing ) {
			var notice = document.createElement( 'div' );
			notice.className = 'pva-demo-notice';
			notice.id        = 'pva-demo-notice';
			notice.innerHTML  = '<svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/></svg>'
				+ '<span class="pva-demo-notice__text"><strong>Sample data</strong> — this is a preview of what your analytics will look like once real viewers start watching.</span>'
				+ '<button class="pva-demo-exit" type="button">Exit preview</button>';

			var chartsSection = document.getElementById( 'pva-charts-section' );
			if ( chartsSection ) {
				chartsSection.insertAdjacentElement( 'beforebegin', notice );
			}
			notice.querySelector( '.pva-demo-exit' ).addEventListener( 'click', exitDemoMode );
		}

		showLoading();
		render( buildDemoData( activeDays ) );
	}

	function exitDemoMode() {
		demoMode = false;
		var btn = document.getElementById( 'pva-demo-toggle' );
		if ( btn ) btn.classList.remove( 'pva-demo-btn--active' );
		var notice = document.getElementById( 'pva-demo-notice' );
		if ( notice ) notice.remove();
		showLoading();
		fetchData( activeDays );
	}

	// PressVideo brand palette — dark analytics theme
	var C_INDIGO    = '#818cf8';   // bright indigo-400, readable on dark
	var C_INDIGO_LT = '#a5b4fc';  // indigo-300, pops on dark
	var C_INDIGO_XL = '#c7d2fe';  // indigo-200, lightest depth
	var C_DARK      = '#ffffff';   // white — donut center value on dark bg
	var C_MUTED     = 'rgba(255,255,255,0.45)'; // axis ticks on dark
	var C_GRID      = 'rgba(255,255,255,0.07)'; // grid lines on dark
	var TIP_BG      = 'rgba(10,10,24,0.96)';   // near-black tooltip
	var TIP_TITLE   = '#a5b4fc';

	// ── Custom Chart.js plugin: donut center text ─────────────────────
	var donutCenterPlugin = {
		id: 'pvDonutCenter',
		afterDraw: function (chart) {
			if (chart.config.type !== 'doughnut') return;
			var opts = (chart.config.options.plugins || {}).pvDonutCenter;
			if (!opts || !opts.value) return;

			var ctx = chart.ctx;
			var cx  = (chart.chartArea.left + chart.chartArea.right)  / 2;
			var cy  = (chart.chartArea.top  + chart.chartArea.bottom) / 2;

			ctx.save();

			ctx.font         = '800 26px -apple-system, BlinkMacSystemFont, sans-serif';
			ctx.fillStyle    = '#ffffff';
			ctx.textAlign    = 'center';
			ctx.textBaseline = 'middle';
			ctx.fillText(opts.value, cx, cy - 10);

			ctx.font      = '600 11px -apple-system, BlinkMacSystemFont, sans-serif';
			ctx.fillStyle = 'rgba(255,255,255,0.45)';
			ctx.fillText('avg completion', cx, cy + 14);

			ctx.restore();
		},
	};

	// Transparent canvas background plugin — lets the dark card show through.
	var transparentBgPlugin = {
		id: 'pvTransparentBg',
		beforeDraw: function(chart) {
			var ctx = chart.ctx;
			ctx.save();
			ctx.globalCompositeOperation = 'destination-over';
			ctx.fillStyle = 'transparent';
			ctx.fillRect(0, 0, chart.width, chart.height);
			ctx.restore();
		},
	};

	// Register globally so it applies to every chart instance.
	if (window.Chart) {
		Chart.register(donutCenterPlugin);
		Chart.register(transparentBgPlugin);
	}

	// ── Boot ──────────────────────────────────────────────────────────
	function init() {
		bindPills();
		bindDemoBtn();
		// Auto-enter demo mode if site has no play data yet
		if ( ! cfg.hasData ) {
			enterDemoMode();
		} else {
			fetchData( activeDays );
		}
	}

	function bindPills() {
		document.querySelectorAll('.pva-pill').forEach(function (btn) {
			btn.addEventListener('click', function () {
				var days = parseInt(this.dataset.days, 10);
				if (days === activeDays) return;

				document.querySelectorAll('.pva-pill').forEach(function (b) {
					b.classList.remove('pva-pill--active');
				});
				this.classList.add('pva-pill--active');
				activeDays = days;
				showLoading();
				if ( demoMode ) {
					render( buildDemoData( activeDays ) );
				} else {
					fetchData( days );
				}
			});
		});
	}

	function bindDemoBtn() {
		var btn = document.getElementById( 'pva-demo-toggle' );
		if ( btn ) {
			btn.addEventListener( 'click', function() {
				if ( demoMode ) exitDemoMode(); else enterDemoMode();
			} );
		}
	}

	function showLoading() {
		// Reset stat values
		['pva-total-plays', 'pva-unique-videos', 'pva-avg-completion'].forEach(function (id) {
			var el = document.getElementById(id);
			if (el) el.textContent = '—';
		});

		// Show skeleton loaders, hide canvases
		document.querySelectorAll('.pva-loading').forEach(function (el) {
			el.removeAttribute('hidden');
		});

		// Reset table
		var tbl = document.getElementById('pva-table-wrap');
		if (tbl) {
			tbl.innerHTML = '<div class="pva-loading" style="padding:16px">'
				+ '<div class="pva-skeleton pva-skeleton--row"></div>'
				+ '<div class="pva-skeleton pva-skeleton--row"></div>'
				+ '<div class="pva-skeleton pva-skeleton--row"></div>'
				+ '</div>';
		}
	}

	function fetchData(days) {
		var body = new URLSearchParams({
			action: 'pv_analytics_data',
			nonce:  nonce,
			days:   days,
		});

		fetch(ajaxUrl, { method: 'POST', body: body })
			.then(function (r) { return r.json(); })
			.then(function (resp) {
				if (resp && resp.success) render(resp.data);
			})
			.catch(function (err) {
				console.error('[PressVideo Analytics]', err);
			});
	}

	function render(data) {
		var hasData = data.stats.total_plays > 0;

		// ── Stats always visible ──────────────────────────────────────
		setText('pva-total-plays',    fmt(data.stats.total_plays));
		setText('pva-unique-videos',  fmt(data.stats.unique_videos));
		setText('pva-avg-completion', data.stats.avg_completion + '%');

		// ── Toggle sections ───────────────────────────────────────────
		var chartsSection = document.getElementById('pva-charts-section');
		var emptySection  = document.getElementById('pva-empty');

		if (chartsSection) chartsSection.hidden = !hasData;
		if (emptySection)  emptySection.hidden  = hasData;

		if (!hasData) return;

		renderTrend(data.trend);
		renderTop(data.top_videos);
		renderDepth(data.depth, data.stats.avg_completion);
		renderTable(data.all_videos);
	}

	// ── Play Trend (line chart) ───────────────────────────────────────
	function renderTrend(trend) {
		hideLoader('pva-trend-loading');

		var sub = document.getElementById('pva-trend-sub');
		if (sub) {
			var total = trend.values.reduce(function (a, b) { return a + b; }, 0);
			sub.textContent = fmt(total) + ' plays this period';
		}

		var ctx = document.getElementById('pva-trend-chart');
		if (!ctx) return;

		var chart2d  = ctx.getContext('2d');
		var gradient = chart2d.createLinearGradient(0, 0, 0, 280);
		gradient.addColorStop(0,   'rgba(165, 180, 252, 0.28)');
		gradient.addColorStop(0.6, 'rgba(165, 180, 252, 0.08)');
		gradient.addColorStop(1,   'rgba(165, 180, 252, 0)');

		var labels = trend.labels.map(function (d) {
			var parts = d.split('-');
			return new Date(parseInt(parts[0], 10), parseInt(parts[1], 10) - 1, parseInt(parts[2], 10))
				.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
		});

		if (trendChart) trendChart.destroy();
		trendChart = new Chart(ctx, {
			type: 'line',
			data: {
				labels: labels,
				datasets: [{
					label:               'Plays',
					data:                trend.values,
					borderColor:         '#a5b4fc',
					backgroundColor:     gradient,
					tension:             0.42,
					pointBackgroundColor: '#a5b4fc',
					pointBorderColor:    'rgba(255,255,255,0.25)',
					pointBorderWidth:    1.5,
					pointRadius:         3.5,
					pointHoverRadius:    7,
					pointHoverBackgroundColor: '#fff',
					fill:                true,
					borderWidth:         2.5,
				}],
			},
			options: {
				responsive:          true,
				maintainAspectRatio: false,
				interaction:         { mode: 'index', intersect: false },
				plugins: {
					legend: { display: false },
					tooltip: {
						backgroundColor: TIP_BG,
						titleColor:      TIP_TITLE,
						bodyColor:       '#fff',
						padding:         12,
						cornerRadius:    8,
						callbacks: {
							label: function (c) {
								return '  ' + c.parsed.y + ' play' + (c.parsed.y !== 1 ? 's' : '');
							},
						},
					},
				},
				scales: {
					x: {
						grid:  { display: false },
						ticks: {
							color:         C_MUTED,
							maxRotation:   0,
							maxTicksLimit: activeDays <= 7 ? 7 : activeDays <= 30 ? 10 : 13,
							font:          { size: 11 },
						},
						border: { display: false },
					},
					y: {
						grid:        { color: C_GRID, drawTicks: false },
						border:      { display: false },
						ticks:       { color: C_MUTED, precision: 0, font: { size: 11 }, padding: 6 },
						beginAtZero: true,
					},
				},
			},
		});
	}

	// ── Top Videos (horizontal bar chart) ────────────────────────────
	function renderTop(topVideos) {
		hideLoader('pva-top-loading');

		var ctx = document.getElementById('pva-top-chart');
		if (!ctx) return;

		if (!topVideos || !topVideos.length) {
			ctx.parentNode.innerHTML = '<p class="pva-no-data">No plays recorded yet.</p>';
			return;
		}

		var labels = topVideos.map(function (v) {
			return v.title.length > 38 ? v.title.substring(0, 38) + '…' : v.title;
		});
		var values = topVideos.map(function (v) { return v.plays; });

		// Bright indigo fading to muted — designed for dark card bg
		var colors = topVideos.map(function (_, i) {
			var alpha = 1 - (i / Math.max(topVideos.length, 1)) * 0.62;
			return 'rgba(129, 140, 248, ' + alpha.toFixed(2) + ')';
		});

		if (topChart) topChart.destroy();
		topChart = new Chart(ctx, {
			type: 'bar',
			data: {
				labels: labels,
				datasets: [{
					label:           'Plays',
					data:            values,
					backgroundColor: colors,
					borderRadius:    6,
					borderSkipped:   false,
				}],
			},
			options: {
				indexAxis:           'y',
				responsive:          true,
				maintainAspectRatio: false,
				plugins: {
					legend: { display: false },
					tooltip: {
						backgroundColor: TIP_BG,
						titleColor:      TIP_TITLE,
						bodyColor:       '#fff',
						padding:         12,
						cornerRadius:    8,
						callbacks: {
							label: function (c) {
								return '  ' + c.parsed.x + ' play' + (c.parsed.x !== 1 ? 's' : '');
							},
						},
					},
				},
				scales: {
					x: {
						grid:        { color: C_GRID },
						border:      { display: false },
						ticks:       { color: C_MUTED, precision: 0, font: { size: 11 } },
						beginAtZero: true,
					},
					y: {
						grid:  { display: false },
						ticks: { color: 'rgba(255,255,255,0.70)', font: { size: 12 }, padding: 4 },
					},
				},
			},
		});
	}

	// ── Watch Depth (doughnut) ────────────────────────────────────────
	function renderDepth(depth, avgCompletion) {
		hideLoader('pva-depth-loading');

		var ctx = document.getElementById('pva-depth-chart');
		if (!ctx) return;

		var d25  = depth.d25  || 0;
		var d50  = depth.d50  || 0;
		var d75  = depth.d75  || 0;
		var d100 = depth.d100 || 0;
		var total = d25 + d50 + d75 + d100;

		if (total === 0) {
			ctx.parentNode.innerHTML = '<p class="pva-no-data">Depth tracking will appear once viewers watch past 25%.</p>';
			return;
		}

		if (depthChart) depthChart.destroy();
		depthChart = new Chart(ctx, {
			type: 'doughnut',
			data: {
				labels: ['25% watched', '50% watched', '75% watched', '100% watched'],
				datasets: [{
					data:            [d25, d50, d75, d100],
					backgroundColor: [C_INDIGO_XL, C_INDIGO_LT, '#6366f1', C_INDIGO],
					borderWidth:     0,
					hoverOffset:     8,
				}],
			},
			options: {
				responsive:          true,
				maintainAspectRatio: false,
				cutout:              '72%',
				animation:           { animateRotate: true, duration: 700 },
				plugins: {
					legend: {
						position: 'bottom',
						labels: {
							color:        'rgba(255,255,255,0.70)',
							padding:      16,
							font:         { size: 12 },
							boxWidth:     12,
							boxHeight:    12,
							borderRadius: 3,
						},
					},
					tooltip: {
						backgroundColor: TIP_BG,
						titleColor:      TIP_TITLE,
						bodyColor:       '#fff',
						padding:         12,
						cornerRadius:    8,
						callbacks: {
							label: function (c) {
								var val = c.parsed;
								var pct = total ? Math.round((val / total) * 100) : 0;
								return '  ' + fmt(val) + ' sessions (' + pct + '%)';
							},
						},
					},
					pvDonutCenter: {
						value: avgCompletion + '%',
					},
				},
			},
		});
	}

	// ── All Videos table ──────────────────────────────────────────────
	function renderTable(allVideos) {
		var wrap = document.getElementById('pva-table-wrap');
		if (!wrap) return;

		if (!allVideos || !allVideos.length) {
			wrap.innerHTML = '<p class="pva-no-data" style="padding:32px 16px;">No data for this period.</p>';
			return;
		}

		var rows = allVideos.map(function (v) {
			var thumb = v.thumb
				? '<img src="' + esc(v.thumb) + '" alt="" class="pva-thumb" loading="lazy">'
				: '<span class="pva-thumb-empty"></span>';

			var title = v.edit
				? '<a href="' + esc(v.edit) + '" class="pva-title-link" title="' + esc(v.title) + '">' + esc(v.title) + '</a>'
				: '<span class="pva-title-link" title="' + esc(v.title) + '">' + esc(v.title) + '</span>';

			return '<tr>'
				+ '<td class="pva-col-thumb">' + thumb + '</td>'
				+ '<td>' + title + '</td>'
				+ '<td class="pva-col-plays">' + fmt(v.plays) + '</td>'
				+ '<td class="pva-col-last">'  + esc(v.last_played) + '</td>'
				+ '</tr>';
		}).join('');

		wrap.innerHTML = '<table class="pva-table">'
			+ '<thead><tr>'
			+ '<th colspan="2">Video</th>'
			+ '<th>Plays</th>'
			+ '<th>Last Played</th>'
			+ '</tr></thead>'
			+ '<tbody>' + rows + '</tbody>'
			+ '</table>';
	}

	// ── Utility ───────────────────────────────────────────────────────

	function setText(id, val) {
		var el = document.getElementById(id);
		if (el) el.textContent = val;
	}

	function hideLoader(id) {
		var el = document.getElementById(id);
		if (el) el.hidden = true;
	}

	function fmt(n) {
		return Number(n).toLocaleString();
	}

	function esc(str) {
		return String(str || '')
			.replace(/&/g, '&amp;')
			.replace(/</g, '&lt;')
			.replace(/>/g, '&gt;')
			.replace(/"/g, '&quot;');
	}

	if (document.readyState === 'loading') {
		document.addEventListener('DOMContentLoaded', init);
	} else {
		init();
	}
}());
